// Pega o conteúdo da API
const content = $input.first().json.content;

if (!content || !Array.isArray(content)) {
  return [{ json: { erro: "Sem dados", total: 0 } }];
}

let totalFaturado = 0;
const faturamentos = {};
const totalPorLoja = {};

for (const doc of content) {
  // Só processa se jaFaturado = true no documento
  if (!doc.jaFaturado) continue;

  const loja = doc.codigoEmpresa || 'SEM_LOJA';
  const itens = doc.itens || [];

  // Inicializa total da loja se não existir
  if (!totalPorLoja[loja]) {
    totalPorLoja[loja] = 0;
  }

  for (const item of itens) {
    const numeroFaturamento = item.numeroFaturamento;
    const especieFaturamento = item.especieFaturamento;
    const dataFaturamento = item.dataFaturamento;
    const valorItem = item.totalItem || 0;

    totalFaturado += valorItem;
    totalPorLoja[loja] += valorItem;

    // Agrupa por numero_faturamento
    const key = `${loja}-${especieFaturamento || 'SEM'}-${numeroFaturamento || 'SEM'}`;
    if (!faturamentos[key]) {
      faturamentos[key] = {
        loja: loja,
        numero_faturamento: numeroFaturamento?.replace(/^0+/, '') || null,
        especie: especieFaturamento || null,
        data_faturamento: dataFaturamento || null,
        valor: 0,
        qtd_itens: 0
      };
    }
    faturamentos[key].valor += valorItem;
    faturamentos[key].qtd_itens += 1;
  }
}

// Formata total por loja
const lojas = Object.entries(totalPorLoja).map(([loja, valor]) => ({
  loja,
  valor: Number(valor.toFixed(2))
})).sort((a, b) => b.valor - a.valor);

return [{
  json: {
    total_faturado: Number(totalFaturado.toFixed(2)),
    total_por_loja: lojas,
    qtd_faturamentos: Object.keys(faturamentos).length,
    detalhes: Object.values(faturamentos)
  }
}];

// Pega o conteúdo da API
const content = $input.first().json.content;

if (!content || !Array.isArray(content)) {
  return [{ json: { erro: "Sem dados", total: 0 } }];
}

// Apenas NF, IF, FF (documentos fiscais - não PD)
const ESPECIES_VALIDAS = ['NF', 'IF', 'FF'];

let totalGeral = 0;
const totalPorLoja = {};
const detalhesPorLoja = {};
const documentosProcessados = new Set();

for (const doc of content) {
  // Só pega documentos já faturados
  if (!doc.jaFaturado) continue;

  const loja = doc.codigoEmpresa || 'SEM_LOJA';
  const itens = doc.itens || [];
  const valorContabil = doc.valorContabil || 0;
  const numeroDocumento = doc.numeroDocumento?.replace(/^0+/, '') || '';
  const especieDocumento = doc.especieDocumento || '';
  const dataEntrada = doc.dataEntrada || null;
  const cliente = doc.cliente?.nome || doc.nomeConsumidorOuCliente || 'SEM_CLIENTE';

  for (const item of itens) {
    const numeroFaturamento = item.numeroFaturamento;
    const especieFaturamento = item.especieFaturamento;

    // Pula se não tiver especie_faturamento ou numero_faturamento
    if (!especieFaturamento || especieFaturamento.trim() === '') continue;
    if (!numeroFaturamento || numeroFaturamento.trim() === '') continue;

    // Pula se não for NF, IF ou FF (documento fiscal)
    if (!ESPECIES_VALIDAS.includes(especieFaturamento)) continue;

    // Chave única do documento (evita duplicatas)
    const docKey = `${loja}-${especieFaturamento}-${numeroFaturamento}`;

    // Só soma uma vez por documento
    if (!documentosProcessados.has(docKey)) {
      documentosProcessados.add(docKey);

      // Inicializa loja se não existir
      if (!totalPorLoja[loja]) {
        totalPorLoja[loja] = 0;
        detalhesPorLoja[loja] = [];
      }

      totalGeral += valorContabil;
      totalPorLoja[loja] += valorContabil;

      // Adiciona detalhes do documento
      detalhesPorLoja[loja].push({
        numero_documento: numeroDocumento,
        especie_documento: especieDocumento,
        numero_faturamento: numeroFaturamento?.replace(/^0+/, '') || null,
        especie_faturamento: especieFaturamento,
        data_entrada: dataEntrada,
        data_faturamento: item.dataFaturamento || null,
        cliente: cliente,
        produto: item.descricaoProduto || item.descricaoCompleta || 'SEM_PRODUTO',
        codigo_produto: item.codigoProduto || '',
        quantidade: item.quantidade || 1,
        valor_contabil: valorContabil
      });
    }
  }
}

// Formata resumo por loja
const lojas = Object.entries(totalPorLoja).map(([loja, valor]) => ({
  loja,
  qtd_documentos: detalhesPorLoja[loja]?.length || 0,
  valor_total: Number(valor.toFixed(2))
})).sort((a, b) => b.valor_total - a.valor_total);

// Formata detalhes agrupados por loja
const detalhesAgrupados = {};
for (const [loja, detalhes] of Object.entries(detalhesPorLoja)) {
  detalhesAgrupados[loja] = detalhes.sort((a, b) => b.valor_contabil - a.valor_contabil);
}

return [{
  json: {
    total_geral_faturado: Number(totalGeral.toFixed(2)),
    qtd_total_documentos: documentosProcessados.size,
    resumo_por_loja: lojas,
    detalhes_por_loja: detalhesAgrupados
  }
}];

// Extrai TODOS os clientes e suas lojas em uma lista plana
const items = [];

for (const cliente of $input.all()) {
  const lojas = cliente.json.lojas || [];

  // Se lojas vier como string (JSON), parsear
  const lojasArray = typeof lojas === 'string' ? JSON.parse(lojas) : lojas;

  for (const loja of lojasArray) {
    items.push({
      json: {
        // Dados do cliente
        empresa_id: cliente.json.empresa_id,
        nome_cliente: cliente.json.nome_cliente,
        api_url: cliente.json.api_url,
        api_endpoint: cliente.json.api_endpoint || '/consultapedidovenda',

        // Dados da loja
        loja_id: loja.loja_id,
        codigo_loja: loja.codigo,
        nome_loja: loja.nome
      }
    });
  }
}

return items;

